arguments.command:
cd /tmp/sv-6fdabd82b147440ea83b8ade7f9b6430/symbols

# Look at ALL local and global symbols (including $x code markers) near these addresses
readelf -s _.debug 2>/dev/null | awk '{
  if (NF >= 8) {
    a = strtonum("0x"$2)
    if (a >= 0x2f0000 && a <= 0x2f5000 && $4 == "FUNC") print
  }
}' | sort -k2 | tail -20

echo "---"
