cd /tmp/sv-6fdabd82b147440ea83b8ade7f9b6430/symbols

# Check sections of the original binary
readelf -S libmonosgen-2.0.so 2>/dev/null | grep -E "\.text|\.rodata|PROGBITS" | head -10

# Check what section these addresses fall in
readelf -S libmonosgen-2.0.so 2>/dev/null | awk '/PROGBITS|NOBITS/ {
  addr = strtonum("0x"$4)
  if ($6 != "") sz = strtonum("0x"$6); else sz = strtonum("0x"$5)
  if (0x2f4b20 >= addr && 0x2f4b20 < addr + sz) print "0x2f4b20 is in section", $1, $2
